\centering
\caption{Loose null hit counts by (quark, integer power) over $25{,}485$ valid Koide triples. Cells show the number of triples for which $|\mathcal{F}^n - m_q^{\msbar}(\mu_\star)| < \sigma_{m_q}(\mu_\star)$. The observed lepton triple lies in the $(s, n{=}2)$ cell.}
\label{tab:loose}
\renewcommand{\arraystretch}{1.2}
\begin{tabular}{lccc}
\toprule
& $n=1$ & $n=2$ & $n=3$ \\
\midrule
$m_u$ & 0 & 0 & 0 \\
$m_d$ & 0 & 0 & 0 \\
$m_s$ & 0 & \textbf{147} & 0 \\
$m_c$ & 0 & 0 & 45 \\
$m_b$ & 0 & 0 & 15 \\
